"use strict";function wireModalLinks(){document.querySelectorAll(".modal-link:not(.bmf-bound)").forEach(e=>{e.classList.add("bmf-bound");const t=e.getAttribute("data-link")||e.getAttribute("href");modalForm(e,{formURL:t,modalID:"#modal",errorClass:".is-invalid"}),e.addEventListener("click",function(o){o.preventDefault()})})}document.readyState==="loading"?document.addEventListener("DOMContentLoaded",wireModalLinks):wireModalLinks(),window.wireModalLinks=wireModalLinks;
